diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 703065280096..fed478f05f9c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3077,6 +3077,35 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   const APInt *LHSC = nullptr, *RHSC = nullptr;
   match(LHS1, m_APInt(LHSC));
   match(RHS1, m_APInt(RHSC));
+  // (icmp ult (A + B), A) | (icmp ult (A + B), B) --> (icmp ult (A + B), A)
+  // (icmp ugt A, (A + B)) | (icmp ugt B, (A + B)) --> (icmp ugt A, (A + B))
+  // (icmp uge (A + B), A) & (icmp uge (A + B), B) --> (icmp uge (A + B), A)
+  // (icmp ule A, (A + B)) & (icmp ule B, (A + B)) --> (icmp ule A, (A + B))
+  // Which checks for uadd overflow.
+  Value *A, *B;
+  ICmpInst::Predicate UnswappedPredL = PredL;
+  ICmpInst::Predicate UnswappedPredR = PredR;
+  Value *UnswappedLHS0 = LHS0;
+  Value *UnswappedLHS1 = LHS1;
+  Value *UnswappedRHS0 = RHS0;
+  Value *UnswappedRHS1 = RHS1;
+  
+  if (PredL == ICmpInst::ICMP_UGT || PredL == ICmpInst::ICMP_ULE) {
+    UnswappedPredL = ICmpInst::getSwappedPredicate(PredL);
+    std::swap(UnswappedLHS0, UnswappedLHS1);
+  }
+  if (PredR == ICmpInst::ICMP_UGT || PredR == ICmpInst::ICMP_ULE) {
+    UnswappedPredR = ICmpInst::getSwappedPredicate(PredR);
+    std::swap(UnswappedRHS0, UnswappedRHS1);
+  }
+  
+  if ((!IsAnd && UnswappedPredL == ICmpInst::ICMP_ULT && UnswappedPredR == ICmpInst::ICMP_ULT) ||
+      (IsAnd && UnswappedPredL == ICmpInst::ICMP_UGE && UnswappedPredR == ICmpInst::ICMP_UGE)) {
+    if (UnswappedLHS0 == UnswappedRHS0 && match(UnswappedLHS0, m_c_Add(m_Value(A), m_Value(B)))) {
+      if ((UnswappedLHS1 == A && UnswappedRHS1 == B) || (UnswappedLHS1 == B && UnswappedRHS1 == A))
+        return Builder.CreateICmp(PredL, LHS0, LHS1);
+    }
+  }

   // (icmp1 A, B) | (icmp2 A, B) --> (icmp3 A, B)
   // (icmp1 A, B) & (icmp2 A, B) --> (icmp3 A, B)
